        if self._toonSetting then
            self._toonSetting:SetCorverMap(nil, 0)
        end
    else
        if self._coverName == skinName then
            self._coverName = ""
        end
        if self._toonSetting then
            self._toonSetting:RemoveCorverMat(skinName)
        end
    end
end

function LxModelDp:AddCoverMat(skinName)
    self._coverName = skinName
    if not self._toonSetting or string.isempty(skinName) then
        return
    end

    if self._toonSetting:HasCorverMat(skinName) then
        return
    end
    local matName = skinName
    if not string.endswith(matName, '.mat') then
        matName = matName..'.mat'
    end
    local assetPath = "Model/Base"..matName
    self:ClearCoverResRequester()
    self._coverResRequester = LxResUtil.GetAssetRequester(assetPath, typeof(UnityEngine.Material), function(obj)
        local mat = obj
        if IsValid(self._toonSetting) then
            mat.name = skinName
            self._toonSetting:AddCorverMat(skinName, mat, 0)
        end
    end)
    self._coverResRequester:StartRequester()
end
function LxModelDp:SetCoverTex(skinName)
    self._coverName = skinName
    if not self._toonSetting or string.isempty(skinName) then
        self:SetCoverValue(0)
        return
    end

    if not string.endswith(skinName, '.png') then
        skinName = skinName..'.png'
    end
    local assetPath = "Model/Base"..skinName
    self:ClearSkinResRequester()
    self._skinResRequester = LxResUtil.GetAssetRequester(assetPath, typeofTexture, function(obj)
        if obj ~= nil then
            if self._toonSetting then
                local caverValue = self._coverValue or 0
                self._toonSetting:SetCorverMap(obj, caverValue)
            end
        end
    end)
    self._skinResRequester:StartRequester()
end

function LxModelDp:ClearCorverSkin()
    self._coverValue = 0
    self._coverName = ''
    if self._toonSetting then
        self._toonSetting:ClearCorverMat()
        self._toonSetting:SetCorverMap(nil, 0)
    end
end

